args.sparql:
SELECT ?city ?label WHERE { 
  { ?city wdt:P131 wd:Q13704 } 
  UNION 
  { 
    wd:Q13704 wdt:P150 ?province .
    ?city wdt:P131 ?province .
  }
  ?city wdt:P1082 ?pop .
  FILTER(?pop = 154137)
  ?city rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}

SELECT ?mall ?mallLabel WHERE {
  ?mall wdt:P31 wd:Q3444983 .  # instance of shopping mall
  ?mall wdt:P131 wd:Q1019949 .  # located in Surigao City
  ?mall rdfs:label ?mallLabel .
  FILTER(LANG(?mallLabel) = "en")
}
